  ('real-estate-moex-01796', 'real-estate', 'real-estate-moex-102-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公平交易法規定裁處停止營業之期間，每次以幾個月為限？', '["六個月", "五個月", "三個月", "二個月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "b925db0a464b", "answer_pdf_sha1": "a82b7a0d612f", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
